import React, { useEffect, useState } from 'react'
import { pondService, environmentLogService } from '../../services/api'
import '../../styles/dashboard.css'
import '../../styles/manager/manager-common.css'
import '../../styles/manager/manager-thresholds.css'

const emptyThresholds = {
  minPh: '',
  maxPh: '',
  minTemp: '',
  maxTemp: '',
  minSalinity: '',
  maxSalinity: '',
  minOxygen: '',
  maxOxygen: '',
  minTurbidity: '',
  maxTurbidity: '',
}

const ManagerThresholds = () => {
  const [ponds, setPonds] = useState([])
  const [selectedPondId, setSelectedPondId] = useState(null)
  const [selectedPond, setSelectedPond] = useState(null)
  const [thresholds, setThresholds] = useState(emptyThresholds)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')

  useEffect(() => {
    fetchPonds()
  }, [])

  const fetchPonds = async () => {
    try {
      setLoading(true)
      const res = await pondService.getAllPonds()
      const pondsList = res?.data?.data || []
      setPonds(pondsList)
      
      // auto-select first pond if available
      if (pondsList.length > 0 && !selectedPondId) {
        const firstPond = pondsList[0]
        setSelectedPondId(firstPond.pond_id)
        setSelectedPond(firstPond)
        await fetchThresholds(firstPond.pond_id)
      }
      setError('')
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tải được danh sách ao')
    } finally {
      setLoading(false)
    }
  }

  const fetchThresholds = async (pondId) => {
    try {
      const res = await environmentLogService.getThresholdsByPond(pondId)
      const data = res?.data?.data
      if (data) {
        setThresholds({
          minPh: data.min_ph ?? '',
          maxPh: data.max_ph ?? '',
          minTemp: data.min_temp ?? '',
          maxTemp: data.max_temp ?? '',
          minSalinity: data.min_salinity ?? '',
          maxSalinity: data.max_salinity ?? '',
          minOxygen: data.min_oxygen ?? '',
          maxOxygen: data.max_oxygen ?? '',
          minTurbidity: data.min_turbidity ?? '',
          maxTurbidity: data.max_turbidity ?? '',
        })
      } else {
        setThresholds(emptyThresholds)
      }
      setError('')
    } catch (err) {
      // if not found, just show empty
      setThresholds(emptyThresholds)
      setError('')
    }
  }

  const handlePondChange = async (pondId) => {
    setSelectedPondId(pondId)
    const pond = ponds.find((p) => String(p.pond_id) === String(pondId))
    setSelectedPond(pond)
    await fetchThresholds(pondId)
    setSuccess('')
  }

  const handleChange = (field, value) => {
    setThresholds((prev) => ({
      ...prev,
      [field]: value === '' ? '' : Number(value),
    }))
  }

  const handleSubmit = async (event) => {
    event.preventDefault()
    if (!selectedPondId) {
      setError('Vui lòng chọn ao')
      return
    }

    try {
      setSaving(true)
      setError('')
      setSuccess('')

      // validate that at least min < max for each metric
      if (thresholds.minPh && thresholds.maxPh && thresholds.minPh > thresholds.maxPh) {
        setError('pH: Min phải nhỏ hơn Max')
        setSaving(false)
        return
      }
      if (thresholds.minTemp && thresholds.maxTemp && thresholds.minTemp > thresholds.maxTemp) {
        setError('Nhiệt độ: Min phải nhỏ hơn Max')
        setSaving(false)
        return
      }
      if (thresholds.minSalinity && thresholds.maxSalinity && thresholds.minSalinity > thresholds.maxSalinity) {
        setError('Độ mặn: Min phải nhỏ hơn Max')
        setSaving(false)
        return
      }
      if (thresholds.minOxygen && thresholds.maxOxygen && thresholds.minOxygen > thresholds.maxOxygen) {
        setError('Oxy: Min phải nhỏ hơn Max')
        setSaving(false)
        return
      }
      if (thresholds.minTurbidity && thresholds.maxTurbidity && thresholds.minTurbidity > thresholds.maxTurbidity) {
        setError('Độ đục: Min phải nhỏ hơn Max')
        setSaving(false)
        return
      }

      const payload = {
        minPh: thresholds.minPh || null,
        maxPh: thresholds.maxPh || null,
        minTemp: thresholds.minTemp || null,
        maxTemp: thresholds.maxTemp || null,
        minSalinity: thresholds.minSalinity || null,
        maxSalinity: thresholds.maxSalinity || null,
        minOxygen: thresholds.minOxygen || null,
        maxOxygen: thresholds.maxOxygen || null,
        minTurbidity: thresholds.minTurbidity || null,
        maxTurbidity: thresholds.maxTurbidity || null,
      }

      await environmentLogService.setThresholdsByPond(selectedPondId, payload)
      setSuccess('✅ Lưu ngưỡng cảnh báo thành công')
      setTimeout(() => setSuccess(''), 3000)
    } catch (err) {
      setError(err?.response?.data?.message || 'Không lưu được ngưỡng cảnh báo')
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return (
      <div className="dashboard-container manager-page">
        <div className="card">
          <p>Đang tải...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard-container manager-page">
      {error && <div className="alert alert-danger">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      <div className="card">
        <h3 style={{ marginBottom: '1.5rem' }}>⚙️ Thiết lập ngưỡng cảnh báo môi trường</h3>

        <div className="threshold-selector">
          <label htmlFor="pond-select">Chọn ao: </label>
          <select
            id="pond-select"
            value={selectedPondId || ''}
            onChange={(e) => handlePondChange(e.target.value)}
            className="form-control"
          >
            <option value="">-- Chọn ao --</option>
            {ponds.map((pond) => (
              <option key={pond.pond_id} value={pond.pond_id}>
                {pond.pond_code} - {pond.pond_name}
              </option>
            ))}
          </select>
        </div>

        {selectedPond && (
          <div className="pond-info">
            <p>
              <strong>Ao: </strong> {selectedPond.pond_code} - {selectedPond.pond_name}
            </p>
            <p>
              <strong>Diện tích: </strong> {selectedPond.area_m2 || '-'} m²
            </p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="thresholds-form">
          <div className="thresholds-grid">
            {/* pH */}
            <div className="threshold-group">
              <h4>🧪 pH</h4>
              <div className="form-row">
                <div className="form-group">
                  <label htmlFor="minPh">Tối thiểu:</label>
                  <input
                    id="minPh"
                    type="number"
                    step="0.1"
                    value={thresholds.minPh}
                    onChange={(e) => handleChange('minPh', e.target.value)}
                    className="form-control"
                    placeholder="Min pH"
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="maxPh">Tối đa:</label>
                  <input
                    id="maxPh"
                    type="number"
                    step="0.1"
                    value={thresholds.maxPh}
                    onChange={(e) => handleChange('maxPh', e.target.value)}
                    className="form-control"
                    placeholder="Max pH"
                  />
                </div>
              </div>
            </div>

            {/* Temperature */}
            <div className="threshold-group">
              <h4>🌡️ Nhiệt độ (°C)</h4>
              <div className="form-row">
                <div className="form-group">
                  <label htmlFor="minTemp">Tối thiểu:</label>
                  <input
                    id="minTemp"
                    type="number"
                    step="0.1"
                    value={thresholds.minTemp}
                    onChange={(e) => handleChange('minTemp', e.target.value)}
                    className="form-control"
                    placeholder="Min Temp"
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="maxTemp">Tối đa:</label>
                  <input
                    id="maxTemp"
                    type="number"
                    step="0.1"
                    value={thresholds.maxTemp}
                    onChange={(e) => handleChange('maxTemp', e.target.value)}
                    className="form-control"
                    placeholder="Max Temp"
                  />
                </div>
              </div>
            </div>

            {/* Salinity */}
            <div className="threshold-group">
              <h4>🧂 Độ mặn (ppt)</h4>
              <div className="form-row">
                <div className="form-group">
                  <label htmlFor="minSalinity">Tối thiểu:</label>
                  <input
                    id="minSalinity"
                    type="number"
                    step="0.1"
                    value={thresholds.minSalinity}
                    onChange={(e) => handleChange('minSalinity', e.target.value)}
                    className="form-control"
                    placeholder="Min Salinity"
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="maxSalinity">Tối đa:</label>
                  <input
                    id="maxSalinity"
                    type="number"
                    step="0.1"
                    value={thresholds.maxSalinity}
                    onChange={(e) => handleChange('maxSalinity', e.target.value)}
                    className="form-control"
                    placeholder="Max Salinity"
                  />
                </div>
              </div>
            </div>

            {/* Oxygen */}
            <div className="threshold-group">
              <h4>💨 Oxy (mg/L)</h4>
              <div className="form-row">
                <div className="form-group">
                  <label htmlFor="minOxygen">Tối thiểu:</label>
                  <input
                    id="minOxygen"
                    type="number"
                    step="0.1"
                    value={thresholds.minOxygen}
                    onChange={(e) => handleChange('minOxygen', e.target.value)}
                    className="form-control"
                    placeholder="Min Oxygen"
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="maxOxygen">Tối đa:</label>
                  <input
                    id="maxOxygen"
                    type="number"
                    step="0.1"
                    value={thresholds.maxOxygen}
                    onChange={(e) => handleChange('maxOxygen', e.target.value)}
                    className="form-control"
                    placeholder="Max Oxygen"
                  />
                </div>
              </div>
            </div>

            {/* Turbidity */}
            <div className="threshold-group">
              <h4>💧 Độ đục (NTU)</h4>
              <div className="form-row">
                <div className="form-group">
                  <label htmlFor="minTurbidity">Tối thiểu:</label>
                  <input
                    id="minTurbidity"
                    type="number"
                    step="0.1"
                    value={thresholds.minTurbidity}
                    onChange={(e) => handleChange('minTurbidity', e.target.value)}
                    className="form-control"
                    placeholder="Min Turbidity"
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="maxTurbidity">Tối đa:</label>
                  <input
                    id="maxTurbidity"
                    type="number"
                    step="0.1"
                    value={thresholds.maxTurbidity}
                    onChange={(e) => handleChange('maxTurbidity', e.target.value)}
                    className="form-control"
                    placeholder="Max Turbidity"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="form-actions" style={{ marginTop: '2rem' }}>
            <button type="submit" className="btn btn-primary" disabled={saving || !selectedPondId}>
              💾 {saving ? 'Đang lưu' : 'Lưu ngưỡng'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

export default ManagerThresholds
